sys_security_acl.script:
answer = (function canViewConfiguredActionParam(grCurrentActionParam) {

	var grConfiguredAction;

	//Return true if user can view the parent configured action.
	grConfiguredAction = grCurrentActionParam.configured_action.getRefRecord();
	if (!grConfiguredAction.isValidRecord()) {
		//If the Configured Action that this Configured Action Parameter references doesn't exist, return false.
		return false;
	}
	return !!grConfiguredAction.canRead();

})(current);
